#include<iostream>
#include<cstdio>
#include<string>
using namespace std;

int sa[10000007];

int main()
{
    int t;
    cin >> t;
    while(t--)
    {
        string s;
        cin >> s;
        int n = s.size();
        s = "*" + s;
        for(int i = 1; i <= n; i++)
        {
            sa[i] = 0;
            int v = 0;
            switch(s[i])
            {
                case 'P': v = 3;break;
                case 'p': v = 2;break;
                case 'G': v = 1;break;
            }
            sa[i] = sa[i - 1] + v;
        }
        int q;
        cin >> q;
        for(int i = 1; i <= q; i++){
            int l, r;
            cin >> l >> r;
            cout << sa[r] - sa[l - 1] << endl;
        }
    }
}
